const checkType = msg.checkType;
const result = msg.payload;

if (checkType === 'register') {
  const username = flow.get('register_username');
  const password = flow.get('register_password');
  if (result && result.length > 0) {
    msg.statusCode = 400;
    msg.payload = { message: 'Username already exists' };
    return [null, msg];
  }
  const now = new Date().toISOString();
  msg.topic = `INSERT INTO users (username, password_hash, created_at) VALUES ('${username.replace(/'/g, "''")}', '${password.replace(/'/g, "''")}', '${now}')`;
  msg.insertType = 'register';
  return [msg, null];

} else if (checkType === 'login') {
  const username = flow.get('login_username');
  const password = flow.get('login_password');
  if (!result || result.length === 0) {
    msg.statusCode = 401;
    msg.payload = { message: 'Invalid username or password' };
    return [null, msg];
  }
  const user = result[0];
  const authMode = user.auth_mode || 'local';
  let passwordValid = false;
  if (authMode === 'server') {
    passwordValid = bcrypt.compareSync(password, user.server_password_hash);
  } else {
    passwordValid = (user.password_hash === password);
  }
  if (!passwordValid) {
    msg.statusCode = 401;
    msg.payload = { message: 'Invalid username or password' };
    return [null, msg];
  }
  const token = Buffer.from(`${user.username}:${Date.now()}`).toString('base64');
  msg.statusCode = 200;
  msg.payload = { token };
  return [null, msg];
}

return [null, msg];

