}

try {
  const token = authHeader.substring(7);
  const decoded = Buffer.from(token, "base64").toString("utf-8");
  const username = decoded.split(":")[0];

  msg.topic = `SELECT id FROM users WHERE username = '${String(username).replace(/'/g, "''")}'`;
  return [msg, null];
} catch (err) {
  msg.statusCode = 401;
  msg.payload = { message: "Invalid token" };
  return [null, msg];
}

// Verify Zone Ownership + validate schedule payload (including duration)

try {
  // 1) Validate user lookup result
  if (!Array.isArray(msg.payload) || msg.payload.length === 0 || msg.payload[0]?.id === undefined) {
    msg.statusCode = 401;
    msg.payload = { message: "User not found" };
    return [null, msg];
  }

  const userId = Number(msg.payload[0].id);

  // 2) Validate zone id
  const zoneId = parseInt(msg.req?.params?.id, 10);

  if (!Number.isFinite(userId)) {
    msg.statusCode = 401;
    msg.payload = { message: "Invalid user ID" };
    return [null, msg];
  }

  if (!Number.isFinite(zoneId)) {
    msg.statusCode = 400;
    msg.payload = { message: "Invalid zone ID" };
    return [null, msg];
  }

  // 3) Parse preserved request body
  let body = msg.req_body;
  if (typeof body === "string") {
    try { body = JSON.parse(body); } catch { body = {}; }
  }
  if (!body || typeof body !== "object") body = {};

  // 4) Parse fields (robust against GUI naming)
  const trigger_metric =
    body.trigger_metric ??
    body.triggerMetric ??
    body.metric ??
    body.metric_id;

  const threshold_kpa =
    body.threshold_kpa ??
    body.thresholdKpa ??
    body.threshold ??
    body.kpa;

  const duration_raw =
    body.duration_minutes ??
    body.durationMinutes ??
    body.duration ??
    body.minutes;

  const enabledRaw =
    body.enabled ??
    body.is_enabled ??
    body.isEnabled;

  // 5) Validate trigger metric
  const allowed = ["SWT_WM1", "SWT_WM2", "SWT_AVG"];
  const trig = String(trigger_metric || "").toUpperCase();

  if (!allowed.includes(trig)) {
    msg.statusCode = 400;
    msg.payload = { message: `Invalid trigger_metric. Allowed: ${allowed.join(", ")}` };
    return [null, msg];
  }

  // 6) Validate threshold
  const th = Number(threshold_kpa);
  if (!Number.isFinite(th) || th <= 0 || th > 300) {
    msg.statusCode = 400;
    msg.payload = { message: "Invalid threshold_kpa (0 < x ≤ 300)" };
    return [null, msg];
  }

  // 7) Validate duration_minutes
  let durationMin =
    duration_raw === undefined || duration_raw === null
      ? 20
      : Number(duration_raw);

  if (!Number.isFinite(durationMin) || durationMin <= 0 || durationMin > 1440) {
    msg.statusCode = 400;
    msg.payload = { message: "Invalid duration_minutes (0 < x ≤ 1440)" };
    return [null, msg];
  }

  durationMin = Math.round(durationMin);

  // 8) Normalize enabled
  const enabledInt =
    enabledRaw === undefined || enabledRaw === null
      ? 1
      : (enabledRaw ? 1 : 0);

  // 9) Store in flow context
  flow.set("sched_user_id", userId);
  flow.set("sched_zone_id", zoneId);
  flow.set("sched_trigger_metric", trig);
  flow.set("sched_threshold_kpa", th);
  flow.set("sched_duration_minutes", durationMin);
  flow.set("sched_enabled", enabledInt);

  // 10) Verify zone belongs to user
  msg.topic = `
    SELECT id
    FROM irrigation_zones
    WHERE id = ${zoneId}
      AND user_id = ${userId}
      AND deleted_at IS NULL
    LIMIT 1;
  `.trim();

  return [msg, null];

} catch (err) {
