// --- helpers
function sqlEscapeString(s) {
  // SQLite string literal escaping: ' -> ''
  return String(s).replace(/'/g, "''");
}

function sqlStringOrNull(v) {
  if (v === undefined || v === null || v === "") return "NULL";
  return `'${sqlEscapeString(v)}'`;
}

function numOrNull(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function sqlNumOrNull(v) {
  const n = numOrNull(v);
  return n === null ? "NULL" : String(n);
}

// --- normalize values
const devEuiRaw = data.devEui || "";
const devEui = String(devEuiRaw).toUpperCase().trim();
if (!devEui) {
