const profiles = [
    { wm1_start: 22, wm2_start: 34, wm1_target: 28, wm2_target: 45, wetProb: 0.008, wm2DiscProb: 0.0003 },
    { wm1_start: 26, wm2_start: 42, wm1_target: 33, wm2_target: 58, wetProb: 0.007, wm2DiscProb: 0.0004 },
    { wm1_start: 18, wm2_start: 38, wm1_target: 26, wm2_target: 52, wetProb: 0.009, wm2DiscProb: 0.0002 },

    { wm1_start: 30, wm2_start: 60, wm1_target: 38, wm2_target: 85, wetProb: 0.006, wm2DiscProb: 0.0006 },
