// Function node with 2 outputs
// Output 1: msg.params for uplink prepared statement (30 params)
// Output 2: array of msgs, each with msg.params for rxinfo prepared statement (9 params)

let p = msg.payload;
if (typeof p === "string") {
  try { p = JSON.parse(p); } catch (e) { return null; }
}
if (!p || typeof p !== "object") return null;

