// --- Optional distance-to-hub (only if you decide to add distance_m column) ---
// Set USE_DISTANCE = true only if you performed the ALTER TABLE.
const USE_DISTANCE = false;

// If you enable it, set hub coordinates here:
const HUB_LAT = 46.997800;   // example
const HUB_LON = 6.932770;    // example

function haversineMeters(lat1, lon1, lat2, lon2) {
  const toRad = (x) => x * Math.PI / 180.0;
  const R = 6371000.0;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon/2)**2;
  return 2 * R * Math.asin(Math.sqrt(a));
}

let distance_m = null;
if (USE_DISTANCE && gps.ok === 1) {
  distance_m = haversineMeters(HUB_LAT, HUB_LON, gps.latitude, gps.longitude);
