    (typeof tx.frequency === "number") ? tx.frequency : null,
    (typeof lora.bandwidth === "number") ? lora.bandwidth : null,
    (typeof lora.spreadingFactor === "number") ? lora.spreadingFactor : null,
    lora.codeRate || null,

