      (typeof rx.snr === "number") ? rx.snr : null,
      (typeof rx.channel === "number") ? rx.channel : null,
      rx.crcStatus || null,
      rx.context || null
    ]
  });
}

return [uplinkMsg, rxMsgs];

// Builds a prepared SQL query + params from optional URL query filters.
// Supports: from, to, dev_eui, gateway_id
// Example:
// /download-fieldtest?from=2026-01-01T00:00:00Z&to=2026-01-02T00:00:00Z&dev_eui=...&gateway_id=...

const q = msg.req?.query || {};

const from = (typeof q.from === 'string' && q.from.trim()) ? q.from.trim() : null;
const to   = (typeof q.to === 'string' && q.to.trim()) ? q.to.trim() : null;
const devEui = (typeof q.dev_eui === 'string' && q.dev_eui.trim()) ? q.dev_eui.trim() : null;
const gwId = (typeof q.gateway_id === 'string' && q.gateway_id.trim()) ? q.gateway_id.trim() : null;

let sql = `
SELECT
  u.ts,
  u.dev_eui,
  u.f_cnt,
  u.dr,
  u.spreading_factor,
  u.frequency_hz,
  u.bandwidth_hz,
  u.code_rate,
  u.confirmed,
  u.latitude,
  u.longitude,
  u.altitude_m,
  u.hdop,
  u.sats,
  u.accuracy_m,
  r.gateway_id,
  r.rssi_dbm,
  r.snr_db,
  r.channel,
  r.crc_status
FROM field_tester_uplinks u
LEFT JOIN field_tester_rxinfo r
  ON u.deduplication_id = r.deduplication_id
WHERE 1=1
`;

const params = [];

if (from) {
  sql += ` AND u.ts >= ?`;
  params.push(from);
}
if (to) {
  sql += ` AND u.ts <= ?`;
  params.push(to);
}
if (devEui) {
  sql += ` AND u.dev_eui = ?`;
  params.push(devEui);
}
if (gwId) {
  sql += ` AND r.gateway_id = ?`;
  params.push(gwId);
}

sql += ` ORDER BY u.ts;`;

// For node-red-node-sqlite you can either:
// - put SQL in msg.topic and params in msg.params (works well), OR
// - configure sqlite node as prepared with fixed SQL (less flexible for filters)
msg.topic = sql;
msg.params = params;

return msg;

// msg.payload is expected to be an array of row objects from sqlite node.
// Convert to CSV and return as downloadable attachment.

const rows = Array.isArray(msg.payload) ? msg.payload : [];

// Helper: CSV escape
function esc(v) {
  if (v === null || v === undefined) return '';
  const s = String(v);
  // Escape quotes by doubling them
  const needsQuotes = /[\n\r,\"]/g.test(s);
  const out = s.replace(/\"/g, '""');
  return needsQuotes ? `"${out}"` : out;
}

// Define a stable column order
const cols = [
  'ts','dev_eui','f_cnt','dr','spreading_factor','frequency_hz','bandwidth_hz','code_rate','confirmed',
  'latitude','longitude','altitude_m','hdop','sats','accuracy_m',
  'gateway_id','rssi_dbm','snr_db','channel','crc_status'
];

let csv = cols.join(',') + '\n';
for (const r of rows) {
  const line = cols.map(c => esc(r?.[c])).join(',');
  csv += line + '\n';
}

// Filename with timestamp
const now = new Date().toISOString().replace(/[:]/g,'-');
const filename = `fieldtest_${now}.csv`;

msg.headers = msg.headers || {};
msg.headers['Content-Type'] = 'text/csv; charset=utf-8';
msg.headers['Content-Disposition'] = `attachment; filename="${filename}"`;

msg.payload = csv;
return msg;

// Exports sensor readings from device_data joined with devices.
// Optional query params: from, to, deveui, zone_id

const q = msg.req?.query || {};

const from   = (typeof q.from === 'string'   && q.from.trim())   ? q.from.trim()   : null;
const to     = (typeof q.to === 'string'     && q.to.trim())     ? q.to.trim()     : null;
const devEui = (typeof q.deveui === 'string' && q.deveui.trim()) ? q.deveui.trim() : null;
const zoneId = (typeof q.zone_id === 'string'&& q.zone_id.trim())? q.zone_id.trim(): null;

let sql = `
SELECT
  dd.recorded_at AS ts,
  dd.deveui      AS deveui,
  d.name         AS device_name,
  d.type_id      AS device_type,
  d.irrigation_zone_id AS zone_id,
  dd.swt_wm1,
  dd.swt_wm2,
  dd.light_lux,
  dd.ambient_temperature,
  dd.relative_humidity
FROM device_data dd
LEFT JOIN devices d
  ON dd.deveui = d.deveui
WHERE 1=1
`;

const params = [];

if (from)   { sql += ` AND dd.recorded_at >= ?`; params.push(from); }
if (to)     { sql += ` AND dd.recorded_at <= ?`; params.push(to); }
if (devEui) { sql += ` AND dd.deveui = ?`; params.push(devEui); }
if (zoneId) { sql += ` AND d.irrigation_zone_id = ?`; params.push(zoneId); }

sql += ` ORDER BY dd.recorded_at;`;

msg.topic = sql;
msg.params = params;
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];

function esc(v) {
  if (v === null || v === undefined) return '';
  const s = String(v);
  const needsQuotes = /[\n\r,\"]/g.test(s);
  const out = s.replace(/\"/g, '""');
  return needsQuotes ? `"${out}"` : out;
}

const cols = [
  'ts','deveui','device_name','device_type','zone_id',
  'swt_wm1','swt_wm2','light_lux','ambient_temperature','relative_humidity'
];

let csv = cols.join(',') + '\n';
for (const r of rows) {
  csv += cols.map(c => esc(r?.[c])).join(',') + '\n';
}

const now = new Date().toISOString().replace(/[:]/g, '-');
const filename = `sensordata_${now}.csv`;

msg.headers = msg.headers || {};
msg.headers['Content-Type'] = 'text/csv; charset=utf-8';
msg.headers['Content-Disposition'] = `attachment; filename="${filename}"`;
msg.payload = csv;
return msg;

msg.statusCode = 500;
msg.headers = { 'Content-Type': 'application/json; charset=utf-8' };
msg.payload = {
  error: 'download-sensordata failed',
  message: msg.error?.message || String(msg.error || 'unknown error')
};
return msg;

var eui = env.get('DEVICE_EUI') || 'UNKNOWN';
var deviceType = env.get('DEVICE_TYPE') || 'GATEWAY';
var fw = env.get('FIRMWARE_VERSION') || '0.4.0';

var os = global.get('os');
var fs = global.get('fs');
var cpuTemp = null, memPercent = null, load1 = null, load5 = null, load15 = null, fanValue = null;

try { cpuTemp = Math.round(parseInt(fs.readFileSync('/sys/class/thermal/thermal_zone0/temp', 'utf8').trim()) / 100) / 10; } catch(e) {}
try {
    var tm = os.totalmem(), fm = os.freemem();
    memPercent = Math.round(((tm - fm) / tm) * 100);
} catch(e) {}
try {
    var la = os.loadavg();
    load1 = Math.round(la[0] * 100) / 100;
    load5 = Math.round(la[1] * 100) / 100;
    load15 = Math.round(la[2] * 100) / 100;
} catch(e) {}
try {
    var period = parseInt(fs.readFileSync('/sys/class/pwm/pwmchip2/pwm3/period', 'utf8').trim());
    var duty = parseInt(fs.readFileSync('/sys/class/pwm/pwmchip2/pwm3/duty_cycle', 'utf8').trim());
    fanValue = Math.round((1 - duty / period) * 255);
} catch(e) {}

msg.topic = 'devices/' + eui + '/heartbeat';
msg.payload = JSON.stringify({
    deviceEui: eui,
    deviceType: deviceType,
    firmwareVersion: fw,
    timestamp: new Date().toISOString(),
    ip: null,
    cpu_temp_c: cpuTemp,
    mem_percent: memPercent,
    load_1: load1,
    load_5: load5,
    load_15: load15,
    fan_value: fanValue
});
msg.qos = 1;
return msg;

var data = msg.payload;
var obj = data.object || {};
var piEui = env.get('DEVICE_EUI') || 'UNKNOWN';

// Publish on the Pi's own topic (ACL is scoped to Pi's username).
// The individual sensor's DevEUI is included in the payload so the server
// can auto-create and route to the correct per-sensor device record.
var sensorEui = (data.deviceInfo && data.deviceInfo.devEui) || piEui;
msg.topic = 'devices/' + piEui + '/telemetry';

// Extract base sensor values
var tempC1 = (typeof obj.TempC1   === 'number') ? obj.TempC1   : null;
var batV   = (typeof obj.BatV     === 'number') ? obj.BatV     : null;
var adcV   = (typeof obj.ADC_CH0V === 'number') ? obj.ADC_CH0V : null;
var swtWm1 = (obj.swt_wm1 != null) ? obj.swt_wm1 : null;
var swtWm2 = (obj.swt_wm2 != null) ? obj.swt_wm2 : null;

// Validate temperature: LSN50 encodes a disconnected DS18B20 as 0x7F,0xFF in
// the raw bytes. ChirpStack's codec may map this to 0 instead of null.
// Check the raw payload bytes to detect the sentinel and null out tempC1.
if (tempC1 !== null && data.data) {
    try {
        var buf = Buffer.from(data.data, 'base64');
        if (buf.length >= 4 && buf[2] === 0x7F && buf[3] === 0xFF) {
            tempC1 = null;
        }
    } catch(e) {}
}

// Dendro calculation (mirrors Sensor_LSN50 logic; separate flow-context key)
var positionMm  = null;
var dendroValid = null;
var deltaMm     = null;
if (adcV !== null) {
    dendroValid = (adcV >= 0 && adcV <= 2.6) ? 1 : 0;
    if (dendroValid) {
        positionMm = Math.round(adcV * 10 * 1000) / 1000;
        var prevKey = 'cloud_dendro_prev_' + sensorEui;
        var prev = flow.get(prevKey);
        if (typeof prev === 'number') {
            deltaMm = Math.round((positionMm - prev) * 1000) / 1000;
        }
        flow.set(prevKey, positionMm);
    }
}

// Infer device type so the server can auto-create with correct type on first uplink
var deviceType = 'KIWI_SENSOR';
if ((batV !== null || adcV !== null || tempC1 !== null) &&
        swtWm1 === null && swtWm2 === null) {
    deviceType = 'DRAGINO_LSN50';
}

msg.payload = JSON.stringify({
    deviceEui: sensorEui,
    deviceType: deviceType,
    timestamp: data.time || new Date().toISOString(),
    swt_wm1: swtWm1,
    swt_wm2: swtWm2,
    light_lux: obj.light_intensity != null ? obj.light_intensity : (obj.light_lux != null ? obj.light_lux : null),
    ambient_temperature: obj.ambient_temperature != null ? obj.ambient_temperature : null,
    relative_humidity: obj.relative_humidity != null ? obj.relative_humidity : null,
    ext_temperature_c: tempC1,
    bat_v: batV,
    adc_ch0v: adcV,
    dendro_position_mm: positionMm,
    dendro_delta_mm: deltaMm,
    dendro_valid: dendroValid
});
msg.qos = 1;
return msg;

var cmd = (typeof msg.payload === 'string') ? JSON.parse(msg.payload) : msg.payload;
var commandType = cmd.commandType || cmd.action || '';
flow.set('lastCommandId', cmd.commandId);
flow.set('lastCommand', cmd);
var piEui = env.get('DEVICE_EUI') || 'UNKNOWN';

if (commandType === 'VALVE_COMMAND') {
    msg.payload = {
        type: 'actuator_command',
        device: { devEui: cmd.devEui || '' },
        data: {
            action: cmd.action,
            duration_minutes: cmd.duration_minutes || 0,
            reason: 'osi_server_command',
            commandId: cmd.commandId
        }
    };
    return [msg, null, null];
} else if (commandType === 'UPDATE_SCHEDULE') {
    msg.payload = cmd;
    return [null, msg, null];
} else if (commandType === 'SET_FAN') {
    var fs = global.get('fs');
    var speed = (typeof cmd.speed === 'number') ? Math.max(0, Math.min(255, Math.round(cmd.speed))) : 0;
    var PWM_CHIP = '/sys/class/pwm/pwmchip2';
    var PWM_CHAN = PWM_CHIP + '/pwm3';
    var PWM_PERIOD = 41566;
    var result = 'SUCCESS';
    try {
        try { fs.accessSync(PWM_CHAN); } catch(e) { fs.writeFileSync(PWM_CHIP + '/export', '3'); }
        var curPeriod = 0;
        try { curPeriod = parseInt(fs.readFileSync(PWM_CHAN + '/period', 'utf8').trim()); } catch(e) {}
        if (curPeriod !== PWM_PERIOD) {
            try { fs.writeFileSync(PWM_CHAN + '/enable', '0'); } catch(e) {}
            fs.writeFileSync(PWM_CHAN + '/period', String(PWM_PERIOD));
        }
        var duty = Math.round((1 - speed / 255) * PWM_PERIOD);
        fs.writeFileSync(PWM_CHAN + '/duty_cycle', String(duty));
        fs.writeFileSync(PWM_CHAN + '/enable', '1');
    } catch(e) { result = 'FAILED: ' + e.message; }
    msg.topic = 'devices/' + piEui + '/command_ack';
    msg.payload = JSON.stringify({ commandId: cmd.commandId, result: result, commandType: commandType });
    msg.qos = 1;
    return [null, null, msg];
} else if (commandType === 'REBOOT') {
    var cp = global.get('cp');
    var result = 'SUCCESS';
    try { setTimeout(function() { cp.exec('reboot'); }, 3000); } catch(e) { result = 'FAILED: ' + e.message; }
    msg.topic = 'devices/' + piEui + '/command_ack';
    msg.payload = JSON.stringify({ commandId: cmd.commandId, result: result, commandType: commandType });
    msg.qos = 1;
    return [null, null, msg];
}
return null;

var cmd = msg.payload;
var zoneId = cmd.zoneId;
var metric = (cmd.triggerMetric || 'SWT_WM1').replace(/'/g, "''");
var threshold = parseFloat(cmd.thresholdKpa) || 0;
var duration = parseInt(cmd.durationMinutes) || 0;
var enabled = cmd.enabled ? 1 : 0;

msg.topic = 'UPDATE irrigation_schedules SET ' +
    'trigger_metric = \'' + metric + '\', ' +
    'threshold_kpa = ' + threshold + ', ' +
    'duration_minutes = ' + duration + ', ' +
    'enabled = ' + enabled + ' ' +
    'WHERE irrigation_zone_id = ' + zoneId;
msg.payload = [];
return msg;

var eui = env.get('DEVICE_EUI') || 'UNKNOWN';
var cmd = flow.get('lastCommand') || {};
msg.topic = 'devices/' + eui + '/command_ack';
msg.payload = JSON.stringify({
    commandId: flow.get('lastCommandId') || null,
    result: 'SUCCESS',
    state: 'SCHEDULE_UPDATED'
});
msg.qos = 1;
return msg;

var eui = env.get('DEVICE_EUI') || 'UNKNOWN';
var commandId = flow.get('lastCommandId');
var ctx = msg._log_ctx || {};
var action = ctx.action || '';
var state = (action === 'OPEN' || action === 'OPEN_FOR_DURATION') ? 'OPEN' : 'CLOSED';
var ts = new Date().toISOString();

var statusMsg = {
    topic: 'devices/' + eui + '/status',
    payload: JSON.stringify({ state: state, timestamp: ts }),
    qos: 1
};
var ackMsg = {
    topic: 'devices/' + eui + '/command_ack',
    payload: JSON.stringify({
        commandId: commandId || null,
        result: 'SUCCESS',
        state: state
    }),
    qos: 1
};
return [statusMsg, ackMsg];

// Decode Dragino LSN50 v2 uplink (ChirpStack already decoded via codec)
// Expects data.object with: TempC1, BatV, ADC_CH0V
// Falls back to raw byte decode from data.data (base64) if object is absent.
// Calculates dendrometer position from ADC via voltage divider (2x100kOhm halves wiper V):
//   position_mm = ADC_V * 10   (valid range: 0-2.6 V ADC -> 0-26 mm)

function decodeRawBytes(b64) {
    try {
        const buf = Buffer.from(b64, 'base64');
        if (buf.length < 11) return null;
        const batV = ((buf[0] << 8) | buf[1]) / 1000;
        const tempRaw = (buf[2] << 24 >> 16) | buf[3];
        const tempC1 = tempRaw / 10;
        const adcV = ((buf[4] << 8) | buf[5]) / 1000;
        // sentinel: disconnected probe
        if (buf[2] === 0x7F && buf[3] === 0xFF) return { batV, tempC1: null, adcV };
        return { batV, tempC1, adcV };
    } catch(e) { return null; }
}

try {
    const data = msg.payload;
    if (!data || !data.deviceInfo) {
        node.error("Unexpected payload structure");
        return null;
    }

    const devEui = String(data.deviceInfo.devEui || '').toUpperCase();
    if (!devEui) { node.error("Missing devEui"); return null; }

    const timestamp = data.time
        ? new Date(data.time).toISOString()
        : new Date().toISOString();

    let tempC1 = null, batV = null, adcV = null;

    if (data.object) {
        // ChirpStack codec decoded — use directly
        const obj = data.object;
        tempC1 = (typeof obj.TempC1 === 'number') ? obj.TempC1 : null;
        batV   = (typeof obj.BatV   === 'number') ? obj.BatV   : null;
        adcV   = (typeof obj.ADC_CH0V === 'number') ? obj.ADC_CH0V : null;
    } else if (data.data) {
        // Fallback: decode raw base64 payload
        const decoded = decodeRawBytes(data.data);
        if (decoded) { tempC1 = decoded.tempC1; batV = decoded.batV; adcV = decoded.adcV; }
    }

    // ---- Dendrometer calculation ----
    let positionMm = null;
    let dendroValid = null;
    let deltaMm = null;

    if (adcV !== null) {
        // Validity: 0–2.6 V ADC; outside this = sensor error or disconnected
        dendroValid = (adcV >= 0 && adcV <= 2.6) ? 1 : 0;

        if (dendroValid) {
            // Voltage divider (2x100kOhm) halves wiper voltage, so V_wiper = ADC_V * 2
            // Potentiometer powered by switched +5 V: position_mm = (V_wiper / 5.0) * 25
            // Simplified: position_mm = ADC_V * 10
            positionMm = Math.round(adcV * 10 * 1000) / 1000;

            // Delta from previous valid reading (per-device flow context)
            const prevKey = 'dendro_prev_' + devEui;
            const prev = flow.get(prevKey);
            if (typeof prev === 'number') {
                deltaMm = Math.round((positionMm - prev) * 1000) / 1000;
            }
            flow.set(prevKey, positionMm);
        }
    }
    // ---------------------------------

    msg.formattedData = { timestamp, devEui, tempC1, batV, adcV, positionMm, dendroValid, deltaMm };

    const parts = [];
    if (tempC1 !== null)     parts.push(`T ${tempC1.toFixed(1)} °C`);
    if (batV   !== null)     parts.push(`Bat ${batV.toFixed(2)} V`);
    if (adcV   !== null)     parts.push(`ADC ${adcV.toFixed(3)} V`);
    if (positionMm !== null) {
        const tag = dendroValid ? `${positionMm.toFixed(2)} mm` : 'INVALID';
        parts.push(`Dendro ${tag}`);
    }
    node.status({ fill: "blue", shape: "dot", text: parts.join(" | ") || "no data" });

    return msg;
} catch(err) {
    node.error("Decode LSN50 error: " + err.message, msg);
    return null;
}

const d = msg.formattedData;
if (!d || !d.devEui) { node.error("formattedData missing", msg); return null; }

function sqlStr(v) {
    if (v === undefined || v === null) return "NULL";
    return `'${String(v).replace(/'/g, "''")}'`;
}
function sqlNum(v) {
    if (v === undefined || v === null) return "NULL";
    const n = Number(v);
    return Number.isFinite(n) ? String(n) : "NULL";
}

const dendroValidSql = (d.dendroValid !== null && d.dendroValid !== undefined)
    ? String(d.dendroValid)
    : 'NULL';

msg.topic = [
    'INSERT INTO device_data',
    '  (deveui, ext_temperature_c, bat_v, adc_ch0v,',
    '   dendro_position_mm, dendro_valid, dendro_delta_mm,',
    '   recorded_at)',
    'VALUES (',
    `  ${sqlStr(d.devEui)},`,
    `  ${sqlNum(d.tempC1)},`,
    `  ${sqlNum(d.batV)},`,
    `  ${sqlNum(d.adcV)},`,
    `  ${sqlNum(d.positionMm)},`,
    `  ${dendroValidSql},`,
    `  ${sqlNum(d.deltaMm)},`,
    `  ${sqlStr(d.timestamp)}`,
    ');'
].join('\n');

msg.payload = msg.topic;
node.status({ fill: "green", shape: "dot", text: `INSERT deveui=${d.devEui}` });
return msg;

const authHeader = msg.req.headers.authorization;
if (!authHeader || !authHeader.startsWith('Bearer ')) {
  msg.statusCode = 401;
  msg.payload = { message: 'Unauthorized' };
  return [null, msg];
}

const deveui = String(msg.req.params.deveui || '').trim().toUpperCase();
if (!deveui) {
  msg.statusCode = 400;
  msg.payload = { message: 'Missing deveui' };
  return [null, msg];
}

const hoursRaw = Number(msg.req.query.hours);
const hours = Number.isFinite(hoursRaw) && hoursRaw > 0 ? hoursRaw : 24;
const cutoff = new Date(Date.now() - hours * 3600 * 1000).toISOString();

msg.topic = [
  'SELECT recorded_at, dendro_position_mm, dendro_delta_mm, adc_ch0v, dendro_valid',
  'FROM device_data',
  `WHERE deveui = '${deveui.replace(/'/g, "''")}' `,
  `  AND dendro_position_mm IS NOT NULL`,
  `  AND recorded_at >= '${cutoff}'`,
  'ORDER BY recorded_at ASC',
  'LIMIT 30000'
].join(' ');

return [msg, null];

const rows = msg.payload || [];
msg.statusCode = 200;
msg.payload = rows.map(r => ({
  t: r.recorded_at,
  position_mm: r.dendro_position_mm,
  delta_mm: r.dendro_delta_mm,
  adc_v: r.adc_ch0v,
  valid: r.dendro_valid
}));
return msg;

const devEui = msg.formattedData && msg.formattedData.devEui;
if (!devEui) { node.error('no devEui in formattedData'); return null; }
msg.topic = `SELECT dendro_enabled, temp_enabled FROM devices WHERE deveui = '${devEui.replace(/'/g, "''")}' LIMIT 1`;
return msg;

const row = Array.isArray(msg.payload) && msg.payload[0];
const dendroEnabled = row && row.dendro_enabled === 1;
const tempEnabled   = row && row.temp_enabled   === 1;

if (!dendroEnabled) {
    msg.formattedData.positionMm  = null;
    msg.formattedData.dendroValid  = null;
    msg.formattedData.deltaMm      = null;
    const prevKey = 'dendro_prev_' + msg.formattedData.devEui;
    flow.set(prevKey, undefined);
}

if (!tempEnabled) {
    msg.formattedData.tempC1 = null;
}

return msg;

const authHeader = msg.req.headers.authorization;
if (!authHeader || !authHeader.startsWith('Bearer ')) {
    msg.statusCode = 401; msg.payload = { message: 'Unauthorized' };
    return [null, msg];
}

const deveui = String(msg.req.params.deveui || '').trim().toUpperCase();
if (!deveui) {
    msg.statusCode = 400; msg.payload = { message: 'Missing deveui' };
    return [null, msg];
}

const body = msg.payload && typeof msg.payload === 'object' ? msg.payload : {};
const enabled = body.enabled === true || body.enabled === 1 ? 1 : 0;

msg.topic = `UPDATE devices SET dendro_enabled = ${enabled} WHERE deveui = '${deveui.replace(/'/g, "''")}'`;
msg._dendro_enabled = enabled;
return [msg, null];

msg.statusCode = 200;
msg.payload = { dendro_enabled: msg._dendro_enabled };
return msg;

const authHeader = msg.req.headers.authorization;
if (!authHeader || !authHeader.startsWith('Bearer ')) {
    msg.statusCode = 401; msg.payload = { message: 'Unauthorized' };
    return [null, msg];
}

const deveui = String(msg.req.params.deveui || '').trim().toUpperCase();
if (!deveui) {
    msg.statusCode = 400; msg.payload = { message: 'Missing deveui' };
    return [null, msg];
}

