return (async () => {

const _db  = new sqlite3.Database('/data/db/farming.db');
const q    = (sql) => new Promise((res,rej) => _db.all(sql, (e,r) => e?rej(e):res(r||[])));
const exec = (sql) => new Promise((res,rej) => _db.run(sql, e => e?rej(e):res(true)));
const close = () => new Promise(res => _db.close(() => res()));
function n(v){return(v===null||v===undefined||!isFinite(Number(v)))?'NULL':String(Number(v));}
function s(v){return(v===null||v===undefined)?'NULL':"'"+String(v).replace(/'/g,"''")+"'";}
const NOW=new Date(), TODAY=NOW.toISOString().slice(0,10);
const WIN_END=NOW.toISOString(), WIN_START=new Date(NOW-86400000).toISOString();
const RANK={none:0,mild:1,moderate:2,significant:3,severe:4};
const NOISE=30;
function round(v,d){if(v==null)return null;return Math.round(v*Math.pow(10,d||0))/Math.pow(10,d||0);}
function median3(vals){
  const h=1;
  return vals.map((_,i)=>{
    const w=vals.slice(Math.max(0,i-h),Math.min(vals.length,i+h+1))
              .filter(v=>v!=null&&isFinite(v)).sort((a,b)=>a-b);
    return w.length?w[Math.floor(w.length/2)]:null;
  });
}
function classifyStress(si,tgrS,tgrH,twdH){
  if(si!=null){if(si<=1.0)return'none';if(si<=1.15)return'mild';if(si<=1.25)return'moderate';if(si<=1.4)return'significant';return'severe';}
  if(tgrS==null)return'none';if(tgrS<0)return'significant';
  if((tgrH||[]).filter(t=>t!=null&&Math.abs(t)<=NOISE).length>=2)return'moderate';
  if((twdH||[]).length>=3){const l=twdH.slice(-3);if(l.every((v,i)=>i===0||(v!=null&&l[i-1]!=null&&v>l[i-1])))return'significant';}
  if(Math.abs(tgrS)<=NOISE)return'mild';return'none';
}
function irrAction(h3,rain){
  if(h3.includes('severe'))return{action:'emergency_irrigate',reasoning:'Severe stress — emergency irrigation required'};
  const c={};for(const l of h3)c[l]=(c[l]||0)+1;
  let d='none';for(const[l,n]of Object.entries(c))if(n>=2&&(RANK[l]||0)>(RANK[d]||0))d=l;
  if(d==='none')       return{action:'decrease_10',  reasoning:'No stress ≥2 of last 3 days — reduce 10%'};
  if(d==='mild')       return{action:'maintain',     reasoning:'Mild stress ≥2 of last 3 days — maintain'};
  if(d==='moderate')   return rain?{action:'maintain',reasoning:'Moderate stress; rain suppresses increase'}
                                  :{action:'increase_10',reasoning:'Moderate stress ≥2 of last 3 days — increase 10%'};
  if(d==='significant')return rain?{action:'increase_10',reasoning:'Significant stress; rain limits to +10%'}
                                  :{action:'increase_20',reasoning:'Significant stress ≥2 of last 3 days — increase 20%'};
  return{action:'maintain',reasoning:'Insufficient data — maintain'};
}
try{
  const zones=await q('SELECT DISTINCT iz.id AS zone_id,iz.name AS zone_name FROM irrigation_zones iz JOIN devices d ON d.irrigation_zone_id=iz.id WHERE d.type_id=\'DRAGINO_LSN50\' AND d.dendro_enabled=1 AND iz.deleted_at IS NULL');
  if(!zones.length){node.status({fill:'grey',shape:'ring',text:'No dendro zones'});msg.payload={success:true,date:TODAY,zones:[]};await close();return msg;}
  const summary=[];
  for(const zone of zones){
    const devs=await q('SELECT deveui,name,COALESCE(is_reference_tree,0) AS is_ref FROM devices WHERE irrigation_zone_id='+zone.zone_id+' AND type_id=\'DRAGINO_LSN50\' AND dendro_enabled=1');
    const trees=[];
    for(const dev of devs){
      const EUI=dev.deveui.replace(/'/g,"''");
      const rows=await q('SELECT position_um,is_valid,is_outlier FROM dendrometer_readings WHERE deveui=\''+EUI+'\' AND recorded_at>=\''+WIN_START+'\' AND recorded_at<\''+WIN_END+'\' ORDER BY recorded_at ASC');
      const vc=rows.filter(r=>r.is_valid===1&&r.is_outlier===0).length;
      const qual=rows.length<10?'insufficient':vc<80?'unreliable':'good';
      const filt=median3(rows.map(r=>(r.is_valid===1&&r.is_outlier===0)?r.position_um:null)).filter(v=>v!=null&&isFinite(v));
      if(!filt.length){trees.push({deveui:dev.deveui,name:dev.name,is_ref:!!dev.is_ref,d_max_um:null,d_min_um:null,mds_um:null,tgr_um:null,tgr_smoothed_um:null,twd_um:null,dr_um:null,recovery_delta_um:null,si:null,stress:'none',qual,vc});continue;}
      const dMax=Math.max(...filt),dMin=Math.min(...filt),mds=dMax-dMin;
      const hist=await q('SELECT date,d_max_um,d_min_um,mds_um,tgr_um,dr_um FROM dendrometer_daily WHERE deveui=\''+EUI+'\' AND date<\''+TODAY+'\' ORDER BY date DESC LIMIT 7');
      const yest=hist[0]||null;
      const tgr=(yest&&yest.d_max_um!=null)?round(dMax-yest.d_max_um,0):null;
      const prevT=hist.slice(0,2).map(r=>r.tgr_um).filter(v=>v!=null);
      const tgrAll=[tgr,...prevT].filter(v=>v!=null);
      const tgrS=tgrAll.length?round(tgrAll.reduce((a,b)=>a+b,0)/tgrAll.length,0):null;
      const pk=await q('SELECT MAX(d_max_um) AS peak FROM dendrometer_daily WHERE deveui=\''+EUI+'\' AND date>=date(\''+TODAY+'\',\'-30 days\')');
      const peak=(pk[0]&&pk[0].peak!=null)?pk[0].peak:dMax;
      const twd=Math.max(0,round(peak-dMax,0));
      const dr=(yest&&yest.d_min_um!=null)?round(dMax-yest.d_min_um,0):null;
      const drA=[dr,...hist.slice(0,6).map(r=>r.dr_um)].filter(v=>v!=null);
      const mA=[mds,...hist.slice(0,6).map(r=>r.mds_um)].filter(v=>v!=null);
      const recD=(drA.length&&mA.length)?round(drA.reduce((a,b)=>a+b)/drA.length-mA.reduce((a,b)=>a+b)/mA.length,0):null;
      trees.push({deveui:dev.deveui,name:dev.name,is_ref:!!dev.is_ref,d_max_um:round(dMax,0),d_min_um:round(dMin,0),mds_um:round(mds,0),tgr_um:tgr,tgr_smoothed_um:tgrS,twd_um:twd,dr_um:dr,recovery_delta_um:recD,si:null,stress:null,qual,vc});
    }
    const ref=trees.find(t=>t.is_ref&&t.mds_um!=null&&t.mds_um>0);
    for(const t of trees){
      if(ref&&!t.is_ref&&t.mds_um!=null)t.si=round(t.mds_um/ref.mds_um,2);
      const EUI=t.deveui.replace(/'/g,"''");
      const tgrH=(await q('SELECT tgr_smoothed_um FROM dendrometer_daily WHERE deveui=\''+EUI+'\' ORDER BY date DESC LIMIT 3')).map(r=>r.tgr_smoothed_um);
      const twdH=(await q('SELECT twd_um FROM dendrometer_daily WHERE deveui=\''+EUI+'\' ORDER BY date DESC LIMIT 3')).map(r=>r.twd_um);
      t.stress=classifyStress(t.si,t.tgr_smoothed_um,tgrH,twdH);
      await exec('INSERT OR REPLACE INTO dendrometer_daily(deveui,date,d_max_um,d_min_um,mds_um,tgr_um,tgr_smoothed_um,twd_um,dr_um,recovery_delta_um,signal_intensity,stress_level,data_quality,valid_readings_count,computed_at)VALUES('+s(t.deveui)+','+s(TODAY)+','+n(t.d_max_um)+','+n(t.d_min_um)+','+n(t.mds_um)+','+n(t.tgr_um)+','+n(t.tgr_smoothed_um)+','+n(t.twd_um)+','+n(t.dr_um)+','+n(t.recovery_delta_um)+','+n(t.si)+','+s(t.stress)+','+s(t.qual)+','+n(t.vc)+','+s(NOW.toISOString())+')');
    }
    const nonRef=trees.filter(t=>!t.is_ref);
    const zoneSt=nonRef.reduce((w,t)=>(RANK[t.stress]||0)>(RANK[w]||0)?t.stress:w,'none');
    const past=(await q('SELECT zone_stress_summary FROM zone_daily_recommendations WHERE zone_id='+zone.zone_id+' AND date<\''+TODAY+'\' ORDER BY date DESC LIMIT 2')).map(r=>r.zone_stress_summary);
    const hist3=[zoneSt,...past].slice(0,3);
    const rr=await q('SELECT rainfall_mm FROM zone_daily_recommendations WHERE zone_id='+zone.zone_id+' ORDER BY date DESC LIMIT 1');
    const hasRain=rr.length&&(rr[0].rainfall_mm||0)>5;
    const{action,reasoning}=irrAction(hist3,hasRain);
    const rec=JSON.stringify({zone_id:String(zone.zone_id),date:TODAY,trees:trees.map(t=>({'tree_id':t.name,'device_eui':t.deveui,'mds_µm':t.mds_um,'tgr_µm':t.tgr_um,'tgr_smoothed_µm':t.tgr_smoothed_um,'twd_µm':t.twd_um,'dr_µm':t.dr_um,'recovery_delta_µm':t.recovery_delta_um,'signal_intensity':t.si,'stress_level':t.stress||'none','data_quality':t.qual})),zone_stress_summary:zoneSt,rainfall_mm:0,water_delivered_liters:0,irrigation_action:action,action_reasoning:reasoning});
    await exec('INSERT OR REPLACE INTO zone_daily_recommendations(zone_id,date,zone_stress_summary,rainfall_mm,water_delivered_liters,irrigation_action,action_reasoning,recommendation_json,computed_at)VALUES('+zone.zone_id+','+s(TODAY)+','+s(zoneSt)+',0,0,'+s(action)+','+s(reasoning)+','+s(rec)+','+s(NOW.toISOString())+')');
    summary.push({zone_id:zone.zone_id,zone:zone.zone_name,stress:zoneSt,action});
    node.log('Zone '+zone.zone_name+': '+zoneSt+' → '+action);
  }
  node.status({fill:'green',shape:'dot',text:TODAY+' — '+zones.length+' zone(s)'});
  msg.payload={success:true,date:TODAY,zones:summary};
  await close(); return msg;
}catch(err){
  node.error('Analytics: '+err.message+'\n'+err.stack);
  node.status({fill:'red',shape:'ring',text:err.message});
  try{await close();}catch(e){}
  return null;
}
})();

