  msg.statusCode=401; msg.payload={error:'Unauthorized'};
  msg.headers={'Access-Control-Allow-Origin':'*'}; return msg;
}

const _db  = new sqlite3.Database('/data/db/farming.db');
const q    = (sql) => new Promise((res,rej) => _db.all(sql, (e,r) => e?rej(e):res(r||[])));
const exec = (sql) => new Promise((res,rej) => _db.run(sql, e => e?rej(e):res(true)));
const close = () => new Promise(res => _db.close(() => res()));
function n(v){return(v===null||v===undefined||!isFinite(Number(v)))?'NULL':String(Number(v));}
function s(v){return(v===null||v===undefined)?'NULL':"'"+String(v).replace(/'/g,"''")+"'";}
function respond(data,code){
  msg.statusCode=code||200; msg.payload=data;
  msg.headers={'Access-Control-Allow-Origin':'*','Content-Type':'application/json'};
  return msg;
}
try{
const deveui=(msg.req.params.deveui||'').toUpperCase().replace(/'/g,"''");
const days=Math.min(Math.max(parseInt(msg.req.query.days)||7,1),90);
const rows=await q('SELECT * FROM dendrometer_daily WHERE deveui=\''+deveui+'\' ORDER BY date DESC LIMIT '+days);
await close(); return respond(rows);
}catch(e){try{await close();}catch(_){} return respond({error:e.message},500);}
})();

